@@ -1,9 +1,40 @@
 export function parseArgs(argv) {
   const result = { _: [] }
-  for (let index = 0; index < argv.length; index += 1) {
-    const arg = argv[index]
-    if (!arg.startsWith('--')) result._.push(arg)
-    else result[arg.slice(2)] = true
+  let i = 0
+  while (i < argv.length) {
+    const arg = argv[i]
+    const next = argv[i + 1]
+    
+    if (!arg.startsWith('-')) {
+      result._.push(arg)
+      i += 1
+    } else if (arg.startsWith('--') && arg.includes('=')) {
+      const key = arg.slice(2, arg.indexOf('='))
+      const value = arg.slice(arg.indexOf('=') + 1)
+      result[key] = value
+      i += 1
+    } else if (arg.startsWith('--')) {
+      result[arg.slice(2)] = true
+      if (next && !next.startsWith('-')) {
+        result[arg.slice(2)] = next
+        i += 2
+      } else {
+        i += 1
+      }
+    } else if (arg.includes('=')) {
+      const key = arg.slice(1, arg.indexOf('='))
+      const value = arg.slice(arg.indexOf('=') + 1)
+      result[key] = value
+      i += 1
+    } else if (arg.startsWith('-')) {
+      result[arg.slice(1)] = true
+      if (next && !next.startsWith('-')) {
+        result[arg.slice(1)] = next
+        i += 2
+      } else {
+        i += 1
+      }
+    }
   }
   return result
-}
+}
